1	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
2	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
3	const LOYALTY_DISCOUNT_RATE = 0.2;
4	const CURSED_SURCHARGE_RATE = 0.5;
5	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
6	const PROCESSING_FEE = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  potion: 40,
11	  amulet: 60,
12	  staff: 80,
13	};
14	
15	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
16	
17	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
18	
19	const totalBasePremium = (items: Item[]): number =>
20	  items.reduce((sum, item) => sum + itemBasePremium(item), 0);
21	
22	const sumSurcharge = (items: Item[], appliesTo: (item: Item) => boolean, rate: number): number =>
23	  items.filter(appliesTo).reduce((sum, item) => sum + itemBasePremium(item) * rate, 0);
24	
25	const conditionalDiscount = (applies: boolean, amount: number, rate: number): number =>
26	  applies ? amount * rate : 0;
27	
28	export function quote(customer: { yearsWithMHPCO: number }, items: Item[], contractIndex: number): number {
29	  const basePremium = totalBasePremium(items);
30	  const cursedSurcharge = sumSurcharge(items, (item) => item.cursed, CURSED_SURCHARGE_RATE);
31	  const enchantmentSurcharge = sumSurcharge(items, (item) => item.enchantment >= 5, HIGH_ENCHANTMENT_SURCHARGE_RATE);
32	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
33	  const followUpDiscount = conditionalDiscount(contractIndex > 0, basePremium, FOLLOW_UP_DISCOUNT_RATE);
34	  const loyaltyDiscount = conditionalDiscount(customer.yearsWithMHPCO >= 2, basePremium, LOYALTY_DISCOUNT_RATE);
35	  return basePremium + cursedSurcharge + enchantmentSurcharge + firstInsuranceSurcharge - followUpDiscount - loyaltyDiscount + PROCESSING_FEE;
36	}
